const QUESTION_COUNT = 10;

export default function QuizPage() {
  const { topicId }   = useParams();
  const { state }     = useLocation();
  const navigate      = useNavigate();
  const { updateScore } = useAuth();

  const [phase, setPhase] = useState("loading");
  const [questions, setQuestions] = useState([]);
  const [topic, setTopic] = useState(state?.topic || null);
  const [current, setCurrent] = useState(0);
  const [selected, setSelected] = useState(null);
  const [revealed, setRevealed] = useState(false);
  const [timeLeft, setTimeLeft] = useState(30);
  const [answers, setAnswers] = useState([]);
  const [error, setError] = useState("");

  const timerRef = useRef(null);
  const startTimeRef = useRef(Date.now());

  // ───────────────────────────────
  // Fetch quiz
  // ───────────────────────────────
  const startQuiz = useCallback(async () => {
    setPhase("loading");
    setError("");
    setAnswers([]);
    setCurrent(0);

    try {
      const { data } = await api.post("/quiz/start", {
        topicId,
        count: QUESTION_COUNT,
      });

      setQuestions(data.questions);
      setTopic(data.topic);
      setPhase("ready");
    } catch (err) {
      setError(err.response?.data?.error || "Failed to load quiz.");
      setPhase("error");
    }
  }, [topicId]);

  useEffect(() => { startQuiz(); }, [startQuiz]);

  // ───────────────────────────────
  // Timer
  // ───────────────────────────────
  useEffect(() => {
    if (phase !== "question" || revealed) return;

    const limit = questions[current]?.timeLimitSeconds || 30;
    setTimeLeft(limit);

    timerRef.current = setInterval(() => {
      setTimeLeft((t) => {
        if (t <= 1) {
          clearInterval(timerRef.current);
          handleTimeout();
          return 0;
        }
        return t - 1;
      });
    }, 1000);

    return () => clearInterval(timerRef.current);
  }, [phase, current, revealed]);

  const handleTimeout = () => {
    if (revealed) return;
    clearInterval(timerRef.current);

    setRevealed(true);
    setSelected(-1);

    setAnswers((prev) => [
      ...prev,
      {
        questionId: questions[current]._id,
        selectedOption: -1,
        timedOut: true,
        timeTakenSeconds: questions[current]?.timeLimitSeconds || 30,
      },
    ]);
  };

  // ───────────────────────────────
  // SELECT ANSWER
  // ───────────────────────────────
  const handleSelect = (optIndex) => {
    if (revealed) return;
    clearInterval(timerRef.current);

    const q = questions[current];
    const timeTaken = (q.timeLimitSeconds || 30) - timeLeft;

    setSelected(optIndex);

    // smooth reveal delay
    setTimeout(() => {
      setRevealed(true);

      setAnswers((prev) => [
        ...prev,
        {
          questionId: q._id,
          selectedOption: optIndex,
          timedOut: false,
          timeTakenSeconds: timeTaken,
        },
      ]);
    }, 250);
  };

  const handleNext = () => {
    setSelected(null);
    setRevealed(false);

    if (current + 1 >= questions.length) {
      submitQuiz();
    } else {
      setCurrent((c) => c + 1);
    }
  };

  // ───────────────────────────────
  // Submit
  // ───────────────────────────────
  const submitQuiz = async () => {
    setPhase("submitting");

    try {
      const totalTime = Math.round((Date.now() - startTimeRef.current) / 1000);

      const { data } = await api.post("/quiz/submit", {
        topicId,
        answers,
        timeTakenSeconds: totalTime,
      });

      updateScore(data.newTotalScore);
      navigate("/results", { state: { result: data, topic, questions } });
    } catch {
      setError("Failed to submit quiz.");
      setPhase("question");
    }
  };

  // ───────────────────────────────
  // UI STATES
  // ───────────────────────────────
  if (phase === "loading" || phase === "submitting") {
    return <div style={{ textAlign: "center", padding: "4rem" }}>Loading…</div>;
  }

  if (phase === "error") {
    return (
      <div style={{ textAlign: "center", padding: "4rem" }}>
        <h2>Error</h2>
        <p>{error}</p>
        <button onClick={startQuiz}>Retry</button>
      </div>
    );
  }

  if (phase === "ready") {
    return (
      <div style={{ textAlign: "center", padding: "3rem" }}>
        <h2>{topic?.name}</h2>
        <button onClick={() => {
          startTimeRef.current = Date.now();
          setPhase("question");
        }}>
          Start Quiz ⚡
        </button>
      </div>
    );
  }

  // ───────────────────────────────
  // QUESTION UI
  // ───────────────────────────────
  const q = questions[current];

  return (
    <div style={{ maxWidth: 700, margin: "auto" }}>
      <h3>Question {current + 1} / {questions.length}</h3>

      <h2 style={{ marginBottom: "1.5rem" }}>{q.text}</h2>

      {/* OPTIONS */}
      {q.options.map((opt, i) => {
        const isSelected = selected === i;
        const isCorrect = revealed && i === q.correctAnswer;
        const isWrong = revealed && isSelected && !isCorrect;

        let bg = "#1a1a22";
        let border = "#333";
        let color = "#fff";

        if (isCorrect) {
          bg = "rgba(34,197,94,0.15)";
          border = "#22c55e";
          color = "#22c55e";
        }

        if (isWrong) {
          bg = "rgba(239,68,68,0.15)";
          border = "#ef4444";
          color = "#ef4444";
        }

        if (!revealed && isSelected) {
          bg = "#2a2a35";
          border = "#6366f1";
        }

        return (
          <button
            key={i}
            onClick={() => handleSelect(i)}
            disabled={revealed}
            style={{
              display: "flex",
              alignItems: "center",
              gap: "10px",
              padding: "12px",
              marginBottom: "10px",
              width: "100%",
              borderRadius: "10px",
              border: `1px solid ${border}`,
              background: bg,
              color,
              cursor: revealed ? "default" : "pointer",
              transition: "0.2s",
            }}
          >
            <strong>{["A","B","C","D"][i]}</strong>
            {opt}


          </button>
        );
      })}

      {/* EXPLANATION */}
      {revealed && q.explanation && (
        <div style={{
          marginTop: "15px",
          padding: "10px",
          background: "#111",
          borderLeft: "3px solid #6366f1"
        }}>
          💡 {q.explanation}
        </div>
      )}

      {/* NEXT BUTTON */}
      {revealed && (
        <button
          onClick={handleNext}
          style={{
            marginTop: "20px",
            padding: "12px",
            width: "100%",
            background: "#6366f1",
            color: "#fff",
            borderRadius: "10px",
            border: "none",
            cursor: "pointer"
          }}
        >
          {current + 1 >= questions.length ? "Submit 🏆" : "Next →"}
        </button>
      )}
    </div>
  );
}
